SD on the earlephilhower core uses the standard SD library. CS pin is the only thing the user has to pick; the SPI peripheral picks up the default SPI pins.

```cpp
#include <Arduino.h>
#include <SPI.h>
#include <SD.h>

const int SD_CS = 17;
const uint32_t INTERVAL_MS = 5000;
uint32_t lastWrite = 0;

void setup() {
  Serial.begin(115200);
  SPI.setSCK(18); SPI.setRX(16); SPI.setTX(19);
  if (!SD.begin(SD_CS)) {
    Serial.println("SD init failed");
    while (true) delay(1000);
  }
}

void loop() {
  if (millis() - lastWrite >= INTERVAL_MS) {
    lastWrite = millis();
    File f = SD.open("log.txt", FILE_WRITE);
    if (f) {
      f.printf("hello %lu\n", millis());
      f.close();
    }
  }
}
```

The Adafruit_EPD library covers SSD1680 panels. Wire DC, RST, BUSY to free GPIOs; using GPIO9, GPIO10, GPIO12 here. CS uses the default SPI CS at GPIO42.

```cpp
#include <Arduino.h>
#include <SPI.h>
#include <Adafruit_EPD.h>

const int EPD_CS    = 42;
const int EPD_DC    = 9;
const int EPD_RST   = 10;
const int EPD_BUSY  = 12;
const int EPD_SRCS  = -1;  // no SRAM chip on the hat

Adafruit_SSD1680 display(122, 250, EPD_DC, EPD_RST, EPD_CS, EPD_SRCS, EPD_BUSY, &SPI);

void setup() {
  display.begin();
  display.clearBuffer();
  display.setRotation(1);
  display.setTextColor(EPD_BLACK);
  display.setTextSize(3);
  int16_t x1, y1; uint16_t w, h;
  display.getTextBounds("hello", 0, 0, &x1, &y1, &w, &h);
  display.setCursor((display.width() - w) / 2, (display.height() - h) / 2);
  display.print("hello");
  display.display();
}

void loop() {}
```

JEDEC ID via 0x9F returns 3 bytes: manufacturer + memory type + capacity.

```cpp
#include <Arduino.h>
#include <SPI.h>

const int FLASH_CS = 10;
const SPISettings settings(8000000, MSBFIRST, SPI_MODE0);

void setup() {
  Serial.begin(115200);
  pinMode(FLASH_CS, OUTPUT);
  digitalWrite(FLASH_CS, HIGH);
  SPI.begin(12, 13, 11, FLASH_CS);

  digitalWrite(FLASH_CS, LOW);
  SPI.beginTransaction(settings);
  SPI.transfer(0x9F);
  uint8_t mfg  = SPI.transfer(0x00);
  uint8_t mem  = SPI.transfer(0x00);
  uint8_t cap  = SPI.transfer(0x00);
  SPI.endTransaction();
  digitalWrite(FLASH_CS, HIGH);

  Serial.printf("JEDEC: %02X %02X %02X\n", mfg, mem, cap);
}

void loop() {}
```

