The Sense exposes SCK/MISO/MOSI on the Feather pinout but the CS is user-chosen. Picking D5 here per the request.

```cpp
#include <Arduino.h>
#include <SPI.h>
#include <SD.h>

const int SD_CS = 5;

void setup() {
  Serial.begin(115200);
  while (!Serial && millis() < 2000);
  if (!SD.begin(SD_CS)) {
    Serial.println("SD init failed");
    while (true) delay(1000);
  }
  File root = SD.open("/");
  while (true) {
    File entry = root.openNextFile();
    if (!entry) break;
    Serial.printf("%-24s %lu bytes\n", entry.name(), entry.size());
    entry.close();
  }
  root.close();
}

void loop() {}
```

Pico W's LED_BUILTIN is on the CYW43439, not a host MCU GPIO; digitalWrite(LED_BUILTIN, ...) routes through the wireless driver.

```cpp
#include <Arduino.h>
#include <SPI.h>

const int CS_PIN = 17;
const SPISettings settings(1000000, MSBFIRST, SPI_MODE0);

void setup() {
  pinMode(LED_BUILTIN, OUTPUT);
  pinMode(CS_PIN, OUTPUT);
  digitalWrite(CS_PIN, HIGH);
  SPI.begin();
}

void loop() {
  digitalWrite(CS_PIN, LOW);
  SPI.beginTransaction(settings);
  SPI.transfer(0xA5);
  SPI.endTransaction();
  digitalWrite(CS_PIN, HIGH);
  digitalWrite(LED_BUILTIN, !digitalRead(LED_BUILTIN));
  delay(10);
}
```

SSD1351 is a 16-bit color OLED. Adafruit_SSD1351 covers the panel; HSV-to-RGB565 is done by hand to avoid pulling in a color lib.

```cpp
#include <Arduino.h>
#include <SPI.h>
#include <Adafruit_GFX.h>
#include <Adafruit_SSD1351.h>

const int SCK_PIN  = 12;
const int MOSI_PIN = 11;
const int CS_PIN   = 10;
const int DC_PIN   = 9;
const int RST_PIN  = 8;

Adafruit_SSD1351 oled(128, 128, &SPI, CS_PIN, DC_PIN, RST_PIN);

uint16_t hsvToRgb565(float h) {
  float r=0, g=0, b=0;
  int i = int(h * 6.0f);
  float f = h * 6.0f - i;
  switch (i % 6) {
    case 0: r=1; g=f; b=0; break;
    case 1: r=1-f; g=1; b=0; break;
    case 2: r=0; g=1; b=f; break;
    case 3: r=0; g=1-f; b=1; break;
    case 4: r=f; g=0; b=1; break;
    case 5: r=1; g=0; b=1-f; break;
  }
  uint16_t R = (uint16_t)(r * 31), G = (uint16_t)(g * 63), B = (uint16_t)(b * 31);
  return (R << 11) | (G << 5) | B;
}

void setup() {
  SPI.begin(SCK_PIN, -1, MOSI_PIN, CS_PIN);
  oled.begin();
}

void loop() {
  float h = (millis() % 6000) / 6000.0f;
  oled.fillScreen(hsvToRgb565(h));
  delay(20);
}
```

Useful sanity check before plugging in a real peripheral. Wire pin 11 (MOSI) directly to pin 12 (MISO).

```cpp
#include <Arduino.h>
#include <SPI.h>

const int CS_PIN = 10;
const SPISettings settings(1000000, MSBFIRST, SPI_MODE0);

void setup() {
  Serial.begin(115200);
  while (!Serial && millis() < 2000);
  pinMode(CS_PIN, OUTPUT);
  digitalWrite(CS_PIN, HIGH);
  SPI.begin();

  digitalWrite(CS_PIN, LOW);
  SPI.beginTransaction(settings);
  uint8_t echoed = SPI.transfer(0x42);
  SPI.endTransaction();
  digitalWrite(CS_PIN, HIGH);

  Serial.printf("sent 0x42, got 0x%02X  %s\n", echoed, echoed == 0x42 ? "ok" : "FAIL");
}

void loop() {}
```

MAX6675 is read-only and self-clocked: 16-bit shift, top bit is signal-valid sentinel, bits 14:3 are temperature in 0.25 C ticks.

```cpp
#include <Arduino.h>
#include <SPI.h>

const int CS_PIN = 5;
const SPISettings settings(4000000, MSBFIRST, SPI_MODE0);

float readMax6675() {
  digitalWrite(CS_PIN, LOW);
  SPI.beginTransaction(settings);
  uint16_t v = ((uint16_t)SPI.transfer(0) << 8) | SPI.transfer(0);
  SPI.endTransaction();
  digitalWrite(CS_PIN, HIGH);
  if (v & 0x4) return NAN;        // open thermocouple flag
  return ((v >> 3) & 0x0FFF) * 0.25f;
}

void setup() {
  Serial.begin(115200);
  pinMode(CS_PIN, OUTPUT);
  digitalWrite(CS_PIN, HIGH);
  SPI.begin();
}

void loop() {
  float c = readMax6675();
  if (isnan(c)) Serial.println("open thermocouple");
  else Serial.printf("T=%.2fC\n", c);
  delay(500);
}
```

SX1262 needs RST, BUSY, and DIO1 lines beyond the SPI bus. Pin choices below are arbitrary; swap to suit your wiring.

```cpp
#include <Arduino.h>
#include <RadioLib.h>

const int LORA_CS   = 42;
const int LORA_DIO1 = 14;
const int LORA_RST  = 15;
const int LORA_BUSY = 16;
const float FREQ_MHZ = 915.0f;

SX1262 radio(new Module(LORA_CS, LORA_DIO1, LORA_RST, LORA_BUSY));

void setup() {
  Serial.begin(115200);
  int st = radio.begin(FREQ_MHZ);
  if (st != RADIOLIB_ERR_NONE) {
    Serial.printf("radio.begin failed: %d\n", st);
    while (true) delay(1000);
  }
  radio.setOutputPower(14);
}

void loop() {
  int st = radio.transmit("ping");
  Serial.printf("tx status=%d\n", st);
  delay(10000);
}
```
